const body = $json.body || {};
const ids = body.ids || [];
if (ids.length === 0) return [{ json: { sql: 'SELECT 1', count: 0 } }];
const esc = (v) => "'" + String(v).replace(/'/g, "''") + "'";
const idList = ids.map(esc).join(',');
return [{ json: { sql: `UPDATE pending_alerts SET read_at = NOW() WHERE id IN (${idList})`, count: ids.length } }];

// Store server data for later
const srvData = $json;
return [{ json: { _servers: srvData } }];

const netData = $json;
const srvData = $('Store Servers').first().json._servers;
return [{ json: { _servers: srvData, _network: netData } }];

const wazData = $json;
const prev = $('Store Network').first().json;
return [{ json: { ...prev, _wazuh: wazData } }];

const insData = $json;
const prev = $('Store Wazuh').first().json;
const srvRaw = prev._servers;
const wazRaw = prev._wazuh;

const now = new Date();
const hourKey = now.toISOString().slice(0, 13);
const alerts = [];

// Parse server data (may be array-wrapped)
const srvObj = Array.isArray(srvRaw) ? srvRaw[0] : srvRaw;
const servers = srvObj?.servers || [];
for (const s of servers) {
  if (s.disk_pused !== null && s.disk_pused !== undefined && s.disk_pused >= 90) {
    alerts.push({
      id: `zabbix-disk-${s.hostid}-${hourKey}`,
      source: 'zabbix', severity: s.disk_pused >= 95 ? 'critical' : 'high',
      title: `Disk space ${Math.round(s.disk_pused)}% on ${s.name}`,
      body: `${s.name} (${s.ip}) root partition at ${s.disk_pused}%`,
      url_hash: '/metrics'
    });
  }
}

// --- Offline-host detection (per-host, time-independent) ---
// Key the alert id on the *set* of offline hosts so it only re-fires when
// that set changes, not every hour. Recovered hosts are auto-resolved by the
// DELETE statement appended below.
const offlineHosts = servers
  .filter(s => s.available === false)
  .map(s => ({ id: s.hostid, name: s.name }))
  .sort((a, b) => String(a.id).localeCompare(String(b.id)));

let currentOfflineId = null;
if (offlineHosts.length > 0) {
  const idTag = offlineHosts.map(h => h.id).join('_');
  currentOfflineId = `zabbix-offline-${idTag}`;
  const names = offlineHosts.map(h => h.name).join(', ');
  alerts.push({
    id: currentOfflineId,
    source: 'zabbix', severity: 'high',
    title: `${offlineHosts.length} server(s) offline`,
    body: `Offline: ${names}`,
    url_hash: '/metrics'
  });
}

// Wazuh
const wazObj = Array.isArray(wazRaw) ? wazRaw[0] : wazRaw;
if (wazObj?.critical_alerts > 0) {
  alerts.push({
    id: `wazuh-critical-${hourKey}`,
    source: 'wazuh', severity: 'critical',
    title: `${wazObj.critical_alerts} critical security alert(s)`,
    body: `Wazuh detected ${wazObj.critical_alerts} critical severity alerts`,
    url_hash: '/security'
  });
}

// Insights
const insObj = Array.isArray(insData) ? insData[0] : insData;
if (insObj?.failed_auth?.total > 10) {
  alerts.push({
    id: `wazuh-auth-${hourKey}`,
    source: 'wazuh', severity: 'high',
    title: `${insObj.failed_auth.total} failed auth attempts`,
    body: `${insObj.failed_auth.total} failed authentication attempts in the last 24h`,
    url_hash: '/security'
  });
}


// Dashboard auth brute-force detection (per-IP rate in past 10 minutes)
const authBurstsRaw = $('Store Auth Bursts').first().json._authBursts;
const authBurstsObj = Array.isArray(authBurstsRaw) ? authBurstsRaw[0] : authBurstsRaw;
const BURST_WARN = 10;      // HIGH: 10+ failures from one IP / 10 min
const BURST_CRIT = 50;      // CRITICAL: 50+ failures from one IP / 10 min
const MINUTE_BUCKET = now.toISOString().slice(0, 16).replace(':', '_'); // 10-min dedup window
for (const ipEvt of (authBurstsObj?.by_ip || [])) {
  if (ipEvt.looks_like_probe) continue;
  if (ipEvt.count >= BURST_CRIT) {
    alerts.push({
      id: `dashauth-brute-crit-${ipEvt.ip}-${MINUTE_BUCKET}`,
      source: 'dashboard-auth', severity: 'critical',
      title: `Brute-force: ${ipEvt.count} auth failures from ${ipEvt.ip}`,
      body: `${ipEvt.ip} has ${ipEvt.count} auth failures in the last 10 min (UAs: ${(ipEvt.user_agents||[]).slice(0,2).join(', ')})`,
      url_hash: '/security'
    });
  } else if (ipEvt.count >= BURST_WARN) {
    alerts.push({
      id: `dashauth-brute-${ipEvt.ip}-${MINUTE_BUCKET}`,
      source: 'dashboard-auth', severity: 'high',
      title: `Suspicious login activity: ${ipEvt.count} from ${ipEvt.ip}`,
      body: `${ipEvt.ip} has ${ipEvt.count} auth failures in the last 10 min`,
      url_hash: '/security'
    });
  }
}

const esc = (v) => v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';

// Auto-resolve: delete any pending zabbix-offline-* rows that don't match the
// current offline set. If nothing is offline, this clears all of them.
const resolveSql = currentOfflineId
  ? `DELETE FROM pending_alerts WHERE id LIKE 'zabbix-offline-%' AND id <> ${esc(currentOfflineId)}`
  : `DELETE FROM pending_alerts WHERE id LIKE 'zabbix-offline-%'`;

const stmts = [resolveSql];
for (const a of alerts) {
  stmts.push(
    `INSERT IGNORE INTO pending_alerts (id, source, severity, title, body, url_hash) VALUES (${esc(a.id)}, ${esc(a.source)}, ${esc(a.severity)}, ${esc(a.title)}, ${esc(a.body)}, ${esc(a.url_hash)})`
  );
}

return [{ json: { sql: stmts.join(';\n'), count: alerts.length, resolveOnly: alerts.length === 0 } }];

// Push each unpushed alert to subscribers via the existing /webpush/send
// endpoint. Returns SQL to mark the successfully-pushed IDs.

const N8N_BASE = 'https://n8n.thisaimachine.com/webhook';
const alerts = $input.all().map(i => i.json).filter(a => a && a.id);

if (alerts.length === 0) {
  return [{ json: { sql: 'SELECT 1', pushed: 0 } }];
}

const pushedIds = [];
for (const a of alerts) {
  const payload = {
    title: a.title || 'Dashboard alert',
    body: a.body || '',
    icon: '/dashboard/logo192.png',
    badge: '/dashboard/logo192.png',
    tag: a.id,
    requireInteraction: a.severity === 'critical',
    data: {
      alert_id: a.id,
      url_hash: a.url_hash || '/',
      severity: a.severity || 'info',
      source: a.source || 'dashboard'
    }
  };
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: N8N_BASE + '/webpush/send',
      body: { payload },
      json: true,
      timeout: 10000,
      ignoreHttpStatusErrors: true
    });
    pushedIds.push(a.id);
  } catch (e) {
    // swallow per-alert failures; we'll retry next cycle since pushed_at stays NULL
  }
}

if (pushedIds.length === 0) {
  return [{ json: { sql: 'SELECT 1', pushed: 0 } }];
}
const list = pushedIds.map(id => "'" + String(id).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'").join(',');
const sql = `UPDATE pending_alerts SET pushed_at = NOW() WHERE id IN (${list})`;
return [{ json: { sql, pushed: pushedIds.length } }];
